// --- Query Depth Limiting Plugin ---
function queryDepthPlugin(maxDepth) {
  return {
    requestDidStart() {
      return {
        didResolveOperation({ document }) {
          const depth = calculateDepth(document);
          if (depth > maxDepth) {
            throw new GraphQLError(
              `Query depth of ${depth} exceeds the maximum allowed depth of ${maxDepth}.`,
              { extensions: { code: 'QUERY_TOO_DEEP' } }
            );
          }
        },
      };
    },
  };
}

function calculateDepth(document, currentDepth = 0) {
  let maxDepth = currentDepth;

  function traverse(selections, depth) {
    if (!selections) return;
    for (const selection of selections) {
      if (selection.kind === 'Field') {
        const newDepth = depth + 1;
        if (newDepth > maxDepth) maxDepth = newDepth;
        if (selection.selectionSet) {
          traverse(selection.selectionSet.selections, newDepth);
        }
      }
      if (selection.kind === 'InlineFragment' && selection.selectionSet) {
        traverse(selection.selectionSet.selections, depth);
      }
    }
  }

  for (const definition of document.definitions) {
    if (definition.kind === 'OperationDefinition' && definition.selectionSet) {
      traverse(definition.selectionSet.selections, 0);
    }
  }

  return maxDepth;
}

